def safe_int(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return False, None, f"ERROR en '{campo}': vacío (raw={valor!r})"
    try:
        return True, int(texto), None
    except ValueError:
        return False, None, f"ERROR en '{campo}': no se pudo convertir {valor!r} a int"

def safe_float(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return False, None, f"ERROR en '{campo}': vacío (raw={valor!r})"
    try:
        return True, float(texto), None
    except ValueError:
        return False, None, f"ERROR en '{campo}': no se pudo convertir {valor!r} a float"

def parse_edad_monto(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {"edad": None, "monto": None}
    errors = []
    ok, n, err = safe_int("edad", edad_txt)
    if ok:
        clean["edad"] = n
    else:
        errors.append(err)
    ok, f, err = safe_float("monto", monto_txt)
    if ok:
        clean["monto"] = f
    else:
        errors.append(err)
    return {"raw": raw, "clean": clean, "errors": errors}

print(parse_edad_monto(" 21 ", "10.5"))
print(parse_edad_monto("abc", "10.5"))
print(parse_edad_monto("21", "xyz"))
